from datetime import datetime
from elasticsearch import Elasticsearch
import json

# Initialize Elasticsearch client
es = Elasticsearch([{'host': 'localhost', 'port': 9200}])

index_name = "logs"
doc_type = "_doc"

def create_index():
    if not es.indices.exists(index=index_name):
        es.indices.create(index=index_name)

def index_document(doc_id, doc):
    res = es.index(index=index_name, doc_type=doc_type, id=doc_id, body=doc)
    return res

def search(query):
    search_res = es.search(index=index_name, body={"query": {"match": { "_all": query }}})
    return search_res["hits"]["hits"]

def log(message):
    log_doc = {
        "timestamp": datetime.now().isoformat(),
        "message": message
    }

    index_document("log-" + str(datetime.now().timestamp()), log_doc)

# Create index before logging anything
create_index()

# Log a few examples
for i in range(10):
    log(f"Example log {i}")

# Search for example logs
results = search("example")
print(results)